// Parser l'input du toolWorkflow
// L'agent peut envoyer juste l'ID ou l'ID + contexte conversationnel
const raw = $input.first().json;
let fullInput = '';
if (raw.query && typeof raw.query === 'string') fullInput = raw.query.trim();
else if (raw.chatInput && typeof raw.chatInput === 'string') fullInput = raw.chatInput.trim();
else if (raw.airtable_id) fullInput = raw.airtable_id.trim();
else {
  for (const [k, v] of Object.entries(raw)) {
    if (typeof v === 'string' && v.length > 3) {
      fullInput = v.trim();
      break;
    }
  }
}

// Extraire l'airtable_id du texte (peut contenir du contexte en plus)
const idMatch = fullInput.match(/(rec[A-Za-z0-9]+|TEST_[A-Za-z0-9_]+)/);
const airtableId = idMatch ? idMatch[1] : '';

// Tout ce qui n'est pas l'ID = contexte conversationnel passé par l'agent
const extraContext = fullInput.replace(airtableId, '').trim();

return [{ json: {
  airtable_id: airtableId,
  extra_context: extraContext,
  has_id: airtableId.length > 0,
  raw_input: fullInput.substring(0, 500)
} }];

// ============================================================
// Construire le prompt : ANALYSE d'abord, GÉNÉRATION si prêt
// ============================================================

const j = $('📋 Charger profil complet').first().json;

if (!j || !j.airtable_id) {
  return [{ json: { skip: true, error: 'Profil non trouvé' } }];
}

const systemPrompt = `Tu es un expert en création de CV pour jeunes en insertion professionnelle (16-25 ans).

Tu reçois TOUTES les données disponibles sur un jeune : profil, notes du mentor, compétences IA, et les conversations WhatsApp récentes (qui peuvent contenir des réponses à des questions que tu as posées précédemment sur son parcours).

TON TRAVAIL EN 2 PHASES :

PHASE 1 — ANALYSE (si pas assez de matière pour un CV pro) :
1. Extraire les expériences DÉJÀ mentionnées (profil, resume_suivi, conversations)
2. Identifier ce qui MANQUE pour un CV de qualité
3. Générer LA PROCHAINE QUESTION à poser (UNE SEULE)

PHASE 2 — GÉNÉRATION (si assez de matière) :
1. Générer le CV complet en JSON

CRITÈRES POUR PASSER EN PHASE 2 (il faut AU MOINS) :
- Le secteur/métier visé est clair
- Au moins 1 expérience (même informelle) avec suffisamment de détail pour rédiger 2-3 lignes de missions
- Les langues parlées sont connues
- On sait si le jeune a un email
Tu peux générer même sans centres d'intérêt ou sans formation détaillée.

RÈGLES POUR LES QUESTIONS :
- UNE question à la fois, jamais deux
- Questions de DÉBLOCAGE (le jeune pense n'avoir rien fait) :
  Mauvais : "As-tu des expériences professionnelles ?"
  Bon : "Tu m'as dit que tu voulais bosser en restauration. T'as déjà aidé en cuisine quelque part, même chez toi ou pour un repas collectif ?"
- Toujours en tutoiement, format WhatsApp court
- Si le jeune a déjà répondu "non" à un sujet, ne pas reposer la même question
- Ordre de priorité : expériences > langues > formation passée > email > centres d'intérêt

RÈGLES POUR LA GÉNÉRATION DU CV :
- Ne JAMAIS mentionner ASE, MNA, foyer, placement, MLDS
- Ne JAMAIS inventer d'expérience
- Valoriser professionnellement chaque fait réel
- Expériences avec CATÉGORIES DE MISSIONS (pas juste des bullet points)
  Ex: "Service : accueil clientèle, prise de commandes, encaissement"
  Ex: "Activité maritime : manipulation des équipements, tri des prises"
- Compétences en catégories : Savoir-faire / Compétences humaines / Compétences linguistiques
- Accroche personnalisée (PAS de copié-collé "Jeune et motivé...")
- UPE2A → "Parcours de Français Langue Étrangère"
- Adresse : SEULEMENT la ville
- Pas de date de naissance, pas de photo

Réponds UNIQUEMENT en JSON :

Si PHASE 1 (pas assez de matière) :
{
  "phase": "collect",
  "data_found": {
    "experiences": ["description courte de chaque expérience trouvée"],
    "formations": ["..."],
    "langues": ["..."],
    "competences": ["..."],
    "email": "oui/non/inconnu"
  },
  "missing": ["ce qui manque encore"],
  "next_question": "la question à poser au jeune (format WhatsApp, tutoiement)",
  "question_context": "pourquoi cette question (pour l'agent)"
}

Si PHASE 2 (assez de matière) :
{
  "phase": "generate",
  "prenom_nom": "...",
  "telephone": "...",
  "email": "...",
  "ville": "...",
  "titre": "...",
  "profil": "... (3-4 lignes d'accroche personnalisée)",
  "experiences": [
    {
      "poste": "...",
      "lieu": "...",
      "dates": "...",
      "categories": [
        { "nom": "...", "detail": "..." }
      ]
    }
  ],
  "formations": [
    { "diplome": "...", "lieu": "...", "dates": "...", "detail": "..." }
  ],
  "competences": [
    { "categorie": "Savoir-faire", "detail": "..." },
    { "categorie": "Compétences humaines", "detail": "..." },
    { "categorie": "Compétences linguistiques", "detail": "..." }
  ],
  "centres_interet": "..."
}`;

const userPrompt = `DONNÉES DU JEUNE :

Identité :
- Prénom : ${j.prenom || ''}
- Nom : ${j.nom || ''}
- Ville : ${j.ville || ''} (${j.departement || ''})
- Téléphone : ${j.telephone || ''}
- Email : ${j.email || 'non renseigné'}
- Genre : ${j.genre || 'non précisé'}

Formation actuelle :
- Classe : ${j.classe || 'non précisée'}
- Secteur visé : ${j.secteur_vise || 'non précisé'}

Profil :
- MNA : ${j.mna ? 'Oui (ne pas mentionner dans le CV)' : 'Non'}
- Niveau français : ${j.niveau_francais_declare || 'non précisé'}
- Disponibilité : ${j.disponibilite || 'non précisée'}
- Besoins exprimés : ${j.besoins || ''}
- Ce qu'il/elle dit de lui/elle : "${(j.attentes_mentor || '').substring(0, 1000)}"

Compétences inférées par IA :
${j.skills_inferees || 'Aucune'}

Notes du mentor (resume_suivi) — cherche des expériences cachées ici :
${(j.resume_suivi || 'Pas de notes disponibles').substring(0, 2000)}

Conversations WhatsApp récentes (peuvent contenir des réponses aux questions CV) :
${(j.conversations_recentes || 'Aucune conversation').substring(0, 2000)}

Analyse et décide : PHASE 1 (poser une question) ou PHASE 2 (générer le CV).`;

return [{ json: { systemPrompt, userPrompt, jeune: j, skip: false } }];

// ============================================================
// Interpréter la réponse Sonnet : question OU CV généré
// ============================================================

const sonnetResp = $('🧠 Claude Sonnet (CV)').first().json;
const jeune = $('📝 Construire prompt CV').first().json.jeune;

let result = {};
try {
  const text = sonnetResp.content?.[0]?.text || '{}';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
} catch(e) {
  return [{ json: { response: 'Erreur lors de l\'analyse du profil. Réessaie.' } }];
}

// === PHASE 1 : Poser une question ===
if (result.phase === 'collect') {
  let response = 'PHASE COLLECTE CV\n\n';
  response += 'Données déjà trouvées :\n';
  if (result.data_found?.experiences?.length > 0) {
    response += '- Expériences : ' + result.data_found.experiences.join(', ') + '\n';
  } else {
    response += '- Expériences : aucune trouvée encore\n';
  }
  if (result.data_found?.langues?.length > 0) {
    response += '- Langues : ' + result.data_found.langues.join(', ') + '\n';
  }
  if (result.data_found?.formations?.length > 0) {
    response += '- Formations : ' + result.data_found.formations.join(', ') + '\n';
  }
  response += '\nIl manque encore : ' + (result.missing || []).join(', ') + '\n';
  response += '\nQUESTION À POSER AU JEUNE (pose-la telle quelle, ne la reformule pas) :\n';
  response += result.next_question + '\n';
  response += '\nContexte : ' + (result.question_context || '');
  response += '\n\nQuand le jeune aura répondu, rappelle cet outil pour continuer la collecte ou générer le CV.';

  return [{ json: { response, phase: 'collect' } }];
}

// === PHASE 2 : Générer le CV HTML ===
const cv = result;

let html = '<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><style>';
html += '@page{size:A4;margin:0}*{margin:0;padding:0;box-sizing:border-box}';
html += 'body{font-family:Georgia,"Times New Roman",serif;font-size:10.5pt;line-height:1.4;color:#1a1a1a;background:white;width:210mm;min-height:297mm;padding:18mm 20mm 15mm 20mm}';
html += '.header{text-align:center;margin-bottom:6mm}.header h1{font-size:22pt;font-weight:bold;letter-spacing:1.5px;margin-bottom:2mm}';
html += '.header .contact{font-size:9.5pt;color:#444;line-height:1.6}.header .contact a{color:#1a5276;text-decoration:none}';
html += '.header .titre{font-size:11pt;font-style:italic;color:#1a5276;margin-top:3mm}';
html += '.section-title{text-align:center;font-size:11pt;font-weight:bold;letter-spacing:2px;text-transform:uppercase;margin-top:5mm;margin-bottom:3mm;border-top:1px solid #1a1a1a;border-bottom:1px solid #1a1a1a;padding:1.5mm 0}';
html += '.profil{font-size:10pt;text-align:justify;line-height:1.5;margin-bottom:2mm;color:#333}';
html += '.exp{margin-bottom:4mm}.exp-header{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:1mm}';
html += '.exp-title{font-weight:bold;font-size:10.5pt;text-transform:uppercase}.exp-dates{font-style:italic;font-size:9pt;color:#555}';
html += '.exp-lieu{font-style:italic;font-size:9.5pt;color:#555;margin-bottom:1.5mm}';
html += '.cat{margin-bottom:1mm;font-size:10pt;line-height:1.45;text-align:justify}.cat-name{font-weight:bold}';
html += '.form{margin-bottom:3mm}.form-header{display:flex;justify-content:space-between;align-items:baseline}';
html += '.form-title{font-weight:bold;font-size:10.5pt;text-transform:uppercase}.form-dates{font-style:italic;font-size:9pt;color:#555}';
html += '.form-lieu{font-style:italic;font-size:9.5pt;color:#555}.form-detail{font-size:9.5pt;color:#333;margin-top:0.5mm}';
html += '.comp-line{margin-bottom:1.5mm;font-size:10pt;line-height:1.5}.comp-cat{font-weight:bold}';
html += '.interets{font-size:10pt;color:#333}';
html += '</style></head><body>';

// Header
html += '<div class="header">';
html += '<h1>' + (cv.prenom_nom || jeune.prenom + ' ' + (jeune.nom || '')) + '</h1>';
html += '<div class="contact">';
if (cv.telephone) html += 'Téléphone : ' + cv.telephone + '<br>';
if (cv.email && cv.email !== 'non renseigné') html += 'Email : <a href="mailto:' + cv.email + '">' + cv.email + '</a>';
html += '</div>';
if (cv.titre) html += '<div class="titre">' + cv.titre + '</div>';
html += '</div>';

// Profil
if (cv.profil) {
  html += '<div class="section-title">Profil</div>';
  html += '<div class="profil">' + cv.profil + '</div>';
}

// Expériences
if (cv.experiences && cv.experiences.length > 0) {
  html += '<div class="section-title">Expérience</div>';
  for (const exp of cv.experiences) {
    html += '<div class="exp">';
    html += '<div class="exp-header"><span class="exp-title">' + (exp.poste||'') + '</span><span class="exp-dates">' + (exp.dates||'') + '</span></div>';
    if (exp.lieu) html += '<div class="exp-lieu">' + exp.lieu + '</div>';
    if (exp.categories) {
      for (const cat of exp.categories) {
        html += '<div class="cat"><span class="cat-name">' + cat.nom + ' : </span>' + cat.detail + '</div>';
      }
    }
    html += '</div>';
  }
}

// Formations
if (cv.formations && cv.formations.length > 0) {
  html += '<div class="section-title">Formation</div>';
  for (const f of cv.formations) {
    html += '<div class="form">';
    html += '<div class="form-header"><span class="form-title">' + (f.diplome||'') + '</span><span class="form-dates">' + (f.dates||'') + '</span></div>';
    if (f.lieu) html += '<div class="form-lieu">' + f.lieu + '</div>';
    if (f.detail) html += '<div class="form-detail">' + f.detail + '</div>';
    html += '</div>';
  }
}

// Compétences
if (cv.competences && cv.competences.length > 0) {
  html += '<div class="section-title">Compétences</div>';
  for (const c of cv.competences) {
    html += '<div class="comp-line"><span class="comp-cat">' + c.categorie + ' : </span>' + c.detail + '</div>';
  }
}

// Centres d'intérêt
if (cv.centres_interet) {
  html += '<div class="section-title">Centres d\'intérêt</div>';
  html += '<div class="interets">' + cv.centres_interet + '</div>';
}

html += '</body></html>';

// Résumé pour l'agent
let summary = 'CV GÉNÉRÉ !\n\n';
summary += 'Titre : ' + (cv.titre || '') + '\n';
summary += 'Profil : ' + (cv.profil || '').substring(0, 150) + '...\n\n';
if (cv.experiences) {
  summary += 'Expériences :\n';
  cv.experiences.forEach(e => { summary += '- ' + e.poste + ' (' + e.dates + ')\n'; });
}
if (cv.formations) {
  summary += '\nFormations :\n';
  cv.formations.forEach(f => { summary += '- ' + f.diplome + ' (' + f.dates + ')\n'; });
}
summary += '\nPrésente ce récap au jeune et demande-lui si c\'est bon ou s\'il veut modifier quelque chose.';
summary += '\nLe HTML du CV est prêt pour conversion en PDF.';

return [{ json: { response: summary, phase: 'generate', cv_html: html, cv_json: cv } }];
